// metro.config.js
const { getDefaultConfig } = require("expo/metro-config");

const config = getDefaultConfig(__dirname);

// Enable package.json "exports" field resolution
// Required for @anthropic-ai/sdk to select its browser build
config.resolver.unstable_enablePackageExports = true;

module.exports = config;

// lib/anthropic.ts — proxy client
const PROXY_URL = process.env.EXPO_PUBLIC_PROXY_URL ?? "https://api.yourapp.com";

export async function chat(messages: { role: string; content: string }[]) {
  const response = await fetch(`${PROXY_URL}/api/chat`, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify({ messages }),
  });

  if (!response.ok) {
    throw new Error(`Proxy error: ${response.status}`);
  }

  const data = await response.json();
  return data.content[0].text as string;
}

// lib/anthropic.ts — direct client (dev prototype only)
import Anthropic from "@anthropic-ai/sdk";

if (!process.env.EXPO_PUBLIC_ANTHROPIC_KEY) {
  throw new Error("EXPO_PUBLIC_ANTHROPIC_KEY is not set");
}

export const anthropic = new Anthropic({
  apiKey: process.env.EXPO_PUBLIC_ANTHROPIC_KEY,
  // dangerouslyAllowBrowser tells the SDK this is intentional
  dangerouslyAllowBrowser: true,
});

// index.js (Expo entry point — before any imports)
import { polyfillGlobal } from "react-native/Libraries/Utilities/PolyfillFunctions";
import { ReadableStream } from "web-streams-polyfill/ponyfill/es6";

// Patch the global ReadableStream before SDK initialises
polyfillGlobal("ReadableStream", () => ReadableStream);

import "expo-router/entry";

// app/index.tsx
import { useState } from "react";
import { Button, ScrollView, StyleSheet, Text, TextInput, View } from "react-native";
import Anthropic from "@anthropic-ai/sdk";

const client = new Anthropic({
  apiKey: process.env.EXPO_PUBLIC_ANTHROPIC_KEY,
  dangerouslyAllowBrowser: true,
});

export default function HomeScreen() {
  const [prompt, setPrompt] = useState("");
  const [response, setResponse] = useState("");
  const [loading, setLoading] = useState(false);

  async function sendMessage() {
    if (!prompt.trim()) return;
    setLoading(true);
    setResponse("");
    try {
      const message = await client.messages.create({
        model: "claude-haiku-4-5-20251001",  // cheapest model for prototyping
        max_tokens: 1024,
        messages: [{ role: "user", content: prompt }],
      });
      const text = message.content
        .filter((b) => b.type === "text")
        .map((b) => b.text)
        .join("");
      setResponse(text);
    } catch (err) {
      setResponse(`Error: ${String(err)}`);
    } finally {
      setLoading(false);
    }
  }

  return (
    <ScrollView contentContainerStyle={styles.container}>
      <TextInput
        style={styles.input}
        value={prompt}
        onChangeText={setPrompt}
        placeholder="Ask Claude..."
        multiline
      />
      <Button title={loading ? "Thinking..." : "Send"} onPress={sendMessage} disabled={loading} />
      {response ? <Text style={styles.response}>{response}</Text> : null}
    </ScrollView>
  );
}

const styles = StyleSheet.create({
  container: { padding: 16, gap: 12 },
  input: { borderWidth: 1, borderColor: "#ccc", borderRadius: 8, padding: 12, minHeight: 80 },
  response: { marginTop: 12, lineHeight: 22 },
});

async function sendStreaming() {
  setLoading(true);
  setResponse("");
  try {
    const stream = await client.messages.stream({
      model: "claude-haiku-4-5-20251001",
      max_tokens: 1024,
      messages: [{ role: "user", content: prompt }],
    });

    for await (const chunk of stream) {
      if (
        chunk.type === "content_block_delta" &&
        chunk.delta.type === "text_delta"
      ) {
        setResponse((prev) => prev + chunk.delta.text);
      }
    }
  } catch (err) {
    setResponse(`Error: ${String(err)}`);
  } finally {
    setLoading(false);
  }
}

useEffect(() => {
  const controller = new AbortController();

  async function load() {
    const msg = await client.messages.create(
      { model: "claude-haiku-4-5-20251001", max_tokens: 512, messages },
      { signal: controller.signal }
    );
    setText(msg.content[0].type === "text" ? msg.content[0].text : "");
  }

  load().catch((e) => {
    if (e.name !== "AbortError") console.error(e);
  });

  return () => controller.abort();
}, [messages]);
